1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survivesOrIsBorn = (neighborCount: number, isAlive: boolean): boolean =>
12	  neighborCount === 3 || (neighborCount === 2 && isAlive);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const alive = new Set(cells.map(keyOf));
16	  const candidates = new Map<string, Cell>();
17	  const neighborCounts = new Map<string, number>();
18	
19	  for (const [x, y] of cells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const neighbor: Cell = [x + dx, y + dy];
22	      const key = keyOf(neighbor);
23	      candidates.set(key, neighbor);
24	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
25	    }
26	  }
27	
28	  return [...candidates]
29	    .filter(([key]) => survivesOrIsBorn(neighborCounts.get(key) ?? 0, alive.has(key)))
30	    .map(([, cell]) => cell);
31	}
