1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells both die (each has 1 neighbor) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 Survival: live cell with 2 neighbors survives — middle cell of horizontal blinker [(0,0),(1,0),(2,0)] keeps (1,0)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
17	      new Set(["1,-1", "1,0", "1,1"])
18	    );
19	  });
20	  it("Rule 3 Overpopulation: live cell with >3 neighbors dies — center (1,1) of 3x3-minus-edges has 6 neighbors and dies", () => {
21	    const result = nextGeneration([
22	      [0, 0], [1, 0], [2, 0],
23	      [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ]);
26	    const set = new Set(result.map((c) => c.join(",")));
27	    expect(set.has("1,1")).toBe(false);
28	  });
29	  it("Rule 4 Reproduction: dead cell with exactly 3 neighbors becomes alive — [(0,0),(1,0),(0,1)] result includes (1,1)", () => {
30	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    const set = new Set(result.map((c) => c.join(",")));
32	    expect(set.has("1,1")).toBe(true);
33	  });
34	  it("Block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same set", () => {
35	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
36	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
37	      new Set(["0,0", "1,0", "0,1", "1,1"])
38	    );
39	  });
40	  it("Blinker oscillator vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
41	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
42	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
43	      new Set(["-1,1", "0,1", "1,1"])
44	    );
45	  });
46	  it("Handles negative coordinates — vertical blinker at (-5,-6..-4) → horizontal at (-6..-4,-5)", () => {
47	    const result = nextGeneration([[-5, -6], [-5, -5], [-5, -4]]);
48	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
49	      new Set(["-6,-5", "-5,-5", "-4,-5"])
50	    );
51	  });
52	});
